const Jimp = require("jimp");

module.exports = {
name: "generate",
description: "Generate an image from text!",
options: [
{
type: "string",
name: "text",
description: "Enter the text you want to turn into an image!",
required: true
}
],
async execute(interaction) {
// Get the text from the interaction
const text = interaction.options.getString("text");

// Create a new image
const image = new Jimp(256, 256, "#FFFFFF");

// Generate the image from the text
Jimp.textLayout(image, text.split(" "), {
x: 16,
y: 16,
size: 32,
align: Jimp.TEXT_ALIGN_CENTER
}, 0);

// Send the image to the user
interaction.reply({
files: [image]
});
}
};

