class Solution:
def isMatch(self, s: str, t: str) -> bool:
dp = [[False] * (len(t)+1) for _ in range(len(s)+1)]
for i in range(len(s)+1):
dp[i][0] = True
if s[i-1] == t[0]:
dp[i][0] = False
dp[i][0] = dp[i-1][0]
for j in range(1, len(t)+1):
if t[j-1] == '*':
dp[i][j] = dp[i-1][j-1]
for k in range(1, len(s)+1):
if t[j-1] == s[k-1]:
dp[i][j] = (dp[i][j-1] or dp[k-1][j]) and dp[k][j+1]
return dp[len(s)][len(t)]

