module.exports = function transform(arr) {
  if (!Array.isArray(arr)) {
    throw new Error('Expected an array');
  }

  const result = [];
  for (let i = 0; i < arr.length; i++) {
    let moddedArr = [...arr[i]];

    if (i < arr.length - 1) {
      moddedArr = moddedArr.map((num, index, arr) => {
        if (index === 0) {
          return num + 1;
        }
        return num;
      });
    }

    result.push(moddedArr);
  }

  return result;
