module.exports = function transform(arr) {
  if (!Array.isArray(arr)) {
    throw new Error('Expected an array');
  }

  if (arr.length === 0) {
    return [];
  }

  const transformedArray = [...arr[0]].map((_, index) => ({ index, value: arr[index] }));
  let currentIndex = 1;

  while (currentIndex < arr.length) {
    let foundMatch = false;
    for (let i = 1; i < transformedArray.length; i++) {
      if (transformedArray[i].value === transformedArray[i - 1].value) {
        foundMatch = true;
        transformedArray[i].index++;
        break;
      }
    }
    if (!foundMatch) {
      break;
    }
    currentIndex++;
  }

  return transformedArray.map(({ index, value }) => value);
};

